-- ----------------------------
-- Table structure for yshop_score_order
-- ----------------------------
DROP TABLE IF EXISTS `yshop_score_order`;
CREATE TABLE `yshop_score_order` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `uid` bigint unsigned NOT NULL COMMENT '用户id',
  `order_id` varchar(100) DEFAULT NULL COMMENT '订单编号',
  `product_id` bigint unsigned NOT NULL COMMENT '商品id',
  `number` int unsigned NOT NULL COMMENT '数量',
  `score` int unsigned NOT NULL COMMENT '实际商品积分',
  `total_score` int unsigned NOT NULL COMMENT '总消耗积分',
  `ip` varchar(30) DEFAULT NULL COMMENT '下单ip',
  `express_sn` varchar(255) DEFAULT NULL COMMENT '快递公司编码',
  `express_number` varchar(50) NOT NULL DEFAULT '' COMMENT '快递编号',
  `express_company` varchar(50) NOT NULL DEFAULT '' COMMENT '快递公司',
  `customer_name` varchar(50) DEFAULT NULL COMMENT '收货名称',
  `customer_phone` varchar(30) DEFAULT NULL COMMENT '收货电话',
  `customer_address` varchar(255) DEFAULT NULL COMMENT '收货地址',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '订单状态:0=取消订单,1=正常啊',
  `have_paid` int NOT NULL DEFAULT '0' COMMENT '已支付:0=否',
  `have_delivered` int NOT NULL DEFAULT '0' COMMENT '已发货:0=否',
  `have_received` int NOT NULL DEFAULT '0' COMMENT '已收货:0=否',
  `create_time` datetime DEFAULT NULL COMMENT '添加时间',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `creator` varchar(64) DEFAULT NULL COMMENT '创建者',
  `updater` varchar(64) DEFAULT NULL COMMENT '更新者',
  `deleted` bit(1) DEFAULT b'0' COMMENT '逻辑删除',
  `tenant_id` bigint NOT NULL DEFAULT '0' COMMENT '租户编号',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `user_id` (`uid`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb3 COMMENT='积分商城订单表';

-- ----------------------------
-- Records of yshop_score_order
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for yshop_score_product
-- ----------------------------
DROP TABLE IF EXISTS `yshop_score_product`;
CREATE TABLE `yshop_score_product` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '产品标题',
  `image` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '主图',
  `images` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '组图',
  `desc` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '详情',
  `score` int NOT NULL DEFAULT '1' COMMENT '消耗积分',
  `weigh` int NOT NULL DEFAULT '0' COMMENT '权重',
  `stock` int unsigned NOT NULL DEFAULT '0' COMMENT '库存',
  `sales` int unsigned NOT NULL DEFAULT '0' COMMENT '销售量',
  `is_switch` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否上架:0=否,1=是',
  `create_time` datetime DEFAULT NULL COMMENT '添加时间',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `creator` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '创建者',
  `updater` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '更新者',
  `deleted` bit(1) DEFAULT b'0' COMMENT '逻辑删除',
  `tenant_id` bigint NOT NULL DEFAULT '0' COMMENT '租户编号',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='积分产品表';

-- ----------------------------
-- Records of yshop_score_product
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for yshop_service
-- ----------------------------
DROP TABLE IF EXISTS `yshop_service`;
CREATE TABLE `yshop_service` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'id',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '标题',
  `image` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '图标',
  `type` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '类型:pages=页面,miniprogram=跳转小程序,menu=菜单,content=内容,call=电话',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '详情',
  `pid` int DEFAULT '0' COMMENT '父级id',
  `app_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '小程序app_id',
  `pages` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '页面路径',
  `phone` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '电话',
  `weigh` int NOT NULL DEFAULT '0' COMMENT '权重',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '状态:0=下架,1=上架',
  `create_time` datetime DEFAULT NULL COMMENT '添加时间',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `creator` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '创建者',
  `updater` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '更新者',
  `deleted` bit(1) DEFAULT b'0' COMMENT '逻辑删除',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `weigh` (`weigh`,`id`)
) ENGINE=InnoDB AUTO_INCREMENT=32 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='我的服务';

-- ----------------------------
-- Records of yshop_service
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for yshop_shipping_templates
-- ----------------------------
DROP TABLE IF EXISTS `yshop_shipping_templates`;
CREATE TABLE `yshop_shipping_templates` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT '模板ID',
  `name` varchar(255) DEFAULT NULL COMMENT '模板名称',
  `type` tinyint(1) DEFAULT NULL COMMENT '计费方式',
  `region_info` text COMMENT '地域以及费用',
  `appoint` tinyint(1) DEFAULT NULL COMMENT '指定包邮开关',
  `appoint_info` text COMMENT '指定包邮内容',
  `creator` varchar(64) DEFAULT NULL COMMENT '创建者',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '添加时间',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `updater` varchar(64) DEFAULT NULL COMMENT '更新者',
  `deleted` bit(1) DEFAULT b'0' COMMENT '是否删除',
  `sort` int DEFAULT NULL COMMENT '排序',
  `tenant_id` bigint DEFAULT NULL COMMENT '租户编号',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=40 DEFAULT CHARSET=utf8mb3 ROW_FORMAT=DYNAMIC COMMENT='运费模板表';

-- ----------------------------
-- Records of yshop_shipping_templates
-- ----------------------------
BEGIN;
COMMIT;

