  `shop_name` varchar(1000) DEFAULT NULL COMMENT '店铺名称逗号隔开',
  `create_time` datetime DEFAULT NULL COMMENT '添加时间',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `creator` varchar(64) DEFAULT NULL COMMENT '创建者',
